module RefModule (  
    input clk,  
    input rst,  
    input [1:0] encoded_in,  
    output reg [1:0] decoded_out  
);  

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin  
    if (rst)  
        decoded_out <= 2'b00;  
    else begin  
        case (encoded_in)  
            2'b00: decoded_out <= 2'b00;  
            2'b01: decoded_out <= 2'b01;  
            2'b10: decoded_out <= 2'b10;  
            2'b11: decoded_out <= 2'b11;  
            default: decoded_out <= 2'b00;  
        endcase  
    end  
end  
endmodule
